export enum Plan {
  Starter = "starter",
  Professional = "professional",
  Enterprise = "enterprise",
}

export type LicenseStatus = "active" | "expired" | "suspended" | "trial";

export interface LicensePayload {
  id: string;
  restaurantId: string;
  plan: Plan;
  status: LicenseStatus;
  issuedAt: string;
  expiresAt: string;
  maxBranches: number;
  maxRegisters: number;
  features: string[];
}
